using System;
using UnityEngine;

/// <summary>Tamanho do texto de diálogo/legendas (Menu de Pausa — Opções, Tarefa #12).</summary>
public enum TextSize
{
    Pequeno,
    Medio,
    Grande
}

/// <summary>
/// Idiomas suportados pela interface/diálogos.
///
/// <b>Estado actual:</b> apenas <see cref="Portugues"/> está habilitado (conteúdo
/// localizado). Os restantes estão definidos no enum para preparar a infraestrutura,
/// mas <see cref="GameSettings.IsLanguageAvailable"/> devolve false para eles — o
/// seletor de idioma ignora-os e volta ao Português.
///
/// <b>Para adicionar um novo idioma:</b>
/// 1. Adicionar a entrada aqui.
/// 2. Marcar como available em <see cref="GameSettings.IsLanguageAvailable"/>.
/// 3. Preencher os dicionários em <see cref="LocalizationManager"/> com as chaves
///    traduzidas.
/// 4. Criar/configurar fontes TMP com suporte ao charset do idioma (ex: japonês
///    exige fonte CJK — ver Guia_HUD_Localizacao.md).
/// </summary>
public enum GameLanguage
{
    Portugues = 0,
    English   = 1,
    Espanhol  = 2,
    Frances   = 3,
    Japones   = 4,
}

/// <summary>
/// Configurações do jogador (Menu de Pausa — Opções, Tarefa #12), distintas do
/// progresso de jogo (PlayerProgress) e das variáveis de eventos (GameVariables):
/// "voz de Gaia - Dublado - OFF", velocidade do texto, tamanho do texto,
/// vibração e idioma.
///
/// Persistido em PlayerPrefs (mesmo padrão de AudioManager — não faz parte de
/// SaveData, porque são preferências do dispositivo/perfil, não do progresso de
/// uma partida).
///
/// Sistemas de diálogo/legendas/UI futuros devem ler
/// <see cref="GaiaVoiceDubbed"/>/<see cref="TextSpeed"/>/<see cref="CurrentTextSize"/>
/// e reagir a <see cref="SettingsChanged"/> para se actualizarem em tempo real
/// quando o jogador muda algo em Opções.
/// </summary>
public class GameSettings : MonoBehaviour
{
    public static GameSettings Instance { get; private set; }

    [Header("Voz de Gaia")]
    [Tooltip("\"Voz de Gaia - Dublado - OFF\": true = falas de Gaia dubladas; false = OFF (sem dublagem, só texto).")]
    [SerializeField] private bool gaiaVoiceDubbed = true;

    [Header("Texto")]
    [Tooltip("Velocidade do texto de diálogo (0 = mais lento, 1 = instantâneo).")]
    [Range(0f, 1f)] [SerializeField] private float textSpeed = 0.5f;

    [SerializeField] private TextSize textSize = TextSize.Medio;

    [Header("Vibração")]
    [SerializeField] private bool vibrationEnabled = true;

    [Header("Acessibilidade (Tarefa #40)")]
    [Tooltip("Screen shake activo. Desligar para jogadores sensíveis a movimentos bruscos de câmara.")]
    [SerializeField] private bool screenShakeEnabled = true;

    [Tooltip("Reduzir flashes intensos (ex: impactos, raios). Substitui efeitos de flash por versões mais suaves.")]
    [SerializeField] private bool reducedFlashes = false;

    [Header("Idioma")]
    [Tooltip("Idioma activo. Por agora apenas Português está disponível (IsLanguageAvailable). Os restantes estão definidos para preparar a infraestrutura — ao serem marcados como disponíveis o seletor passará a aceitá-los. Na primeira execução o idioma é detectado automaticamente pelo sistema via Application.systemLanguage.")]
    [SerializeField] private GameLanguage language = GameLanguage.Portugues;

    [Header("Auras Pós-game (só visível no menu após desbloquear o emblema correspondente)")]
    [Tooltip("Mostrar a Aura de Apolo no player (apenas disponível após obter o Emblema de Apolo). Padrão: ligado.")]
    [SerializeField] private bool apoloAuraEnabled = true;

    [Tooltip("Mostrar a Aura de Gaia no player (apenas disponível após obter o Emblema de Gaia). Padrão: ligado.")]
    [SerializeField] private bool gaiaAuraEnabled = true;

    [Tooltip("Mostrar a Aura de Zeus no player (apenas disponível após obter ambos Apolo + Gaia). Padrão: ligado.")]
    [SerializeField] private bool zeusAuraEnabled = true;

    private const string PrefApoloAura = "settings_apolo_aura_enabled";
    private const string PrefGaiaAura = "settings_gaia_aura_enabled";
    private const string PrefZeusAura = "settings_zeus_aura_enabled";

    private const string PrefGaiaVoiceDubbed = "settings_gaia_voice_dubbed";
    private const string PrefTextSpeed = "settings_text_speed";
    private const string PrefTextSize = "settings_text_size";
    private const string PrefVibration = "settings_vibration_enabled";
    private const string PrefLanguage = "settings_language";
    private const string PrefScreenShake = "settings_screen_shake_enabled";
    private const string PrefReducedFlashes = "settings_reduced_flashes";

    /// <summary>Disparado sempre que uma configuração muda — sistemas de diálogo/UI/legendas/vibração devem subscrever para se actualizarem em tempo real.</summary>
    public event Action SettingsChanged;

    public bool ApoloAuraEnabled => apoloAuraEnabled;
    public bool GaiaAuraEnabled => gaiaAuraEnabled;
    public bool ZeusAuraEnabled => zeusAuraEnabled;

    public bool GaiaVoiceDubbed => gaiaVoiceDubbed;
    public float TextSpeed => textSpeed;
    public TextSize CurrentTextSize => textSize;
    public bool VibrationEnabled => vibrationEnabled;
    public GameLanguage Language => language;
    public bool ScreenShakeEnabled => screenShakeEnabled;
    public bool ReducedFlashes => reducedFlashes;

    /// <summary>
    /// Marca instâncias criadas automaticamente por <see cref="EnsureExists"/>
    /// antes da primeira cena carregar (ver PlayerProgress.cs para a explicação
    /// completa — Tarefa #15 "GameBootstrap e singletons").
    /// </summary>
    private bool isAutoFallback;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            if (Instance.isAutoFallback && !isAutoFallback)
            {
                Destroy(Instance.gameObject);
            }
            else
            {
                Destroy(gameObject);
                return;
            }
        }

        Instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);

        LoadSettings();
    }

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void EnsureExists()
    {
        if (Instance != null) return;
        var go = new GameObject(nameof(GameSettings) + " (Fallback)");
        var instance = go.AddComponent<GameSettings>();
        instance.isAutoFallback = true;
    }

    // ---------------- Setters ----------------

    public void SetGaiaVoiceDubbed(bool value)
    {
        gaiaVoiceDubbed = value;
        PlayerPrefs.SetInt(PrefGaiaVoiceDubbed, value ? 1 : 0);
        NotifyChanged();
    }

    public void SetTextSpeed(float value)
    {
        textSpeed = Mathf.Clamp01(value);
        PlayerPrefs.SetFloat(PrefTextSpeed, textSpeed);
        NotifyChanged();
    }

    public void SetTextSize(TextSize value)
    {
        textSize = value;
        PlayerPrefs.SetInt(PrefTextSize, (int)value);
        NotifyChanged();
    }

    /// <summary>Avança para o próximo tamanho de texto, voltando a "Pequeno" depois de "Grande" — usado pelo botão cíclico de Opções.</summary>
    public void CycleTextSize()
    {
        int next = ((int)textSize + 1) % Enum.GetValues(typeof(TextSize)).Length;
        SetTextSize((TextSize)next);
    }

    public void SetVibrationEnabled(bool value)
    {
        vibrationEnabled = value;
        PlayerPrefs.SetInt(PrefVibration, value ? 1 : 0);
        NotifyChanged();
    }

    public void SetLanguage(GameLanguage value)
    {
        if (!IsLanguageAvailable(value)) return; // ignora idiomas não disponíveis
        language = value;
        PlayerPrefs.SetInt(PrefLanguage, (int)value);
        NotifyChanged();
    }

    /// <summary>
    /// Ordem de exibição dos idiomas no seletor cíclico. Inglês aparece primeiro
    /// (é o idioma de fallback global quando o sistema do jogador não estiver
    /// disponível). A lista completa: EN, PT, ES, FR, JP.
    /// </summary>
    private static readonly GameLanguage[] LanguageCycleOrder =
    {
        GameLanguage.English,
        GameLanguage.Portugues,
        GameLanguage.Espanhol,
        GameLanguage.Frances,
        GameLanguage.Japones,
    };

    /// <summary>
    /// Avança para o próximo idioma disponível na lista (<see cref="LanguageCycleOrder"/>),
    /// voltando ao início depois do último — usado pelo botão cíclico de Opções e
    /// do Menu Principal. Idiomas não disponíveis são ignorados; se nenhum outro
    /// estiver disponível, mantém o actual.
    /// </summary>
    public void CycleLanguage()
    {
        int startIndex = System.Array.IndexOf(LanguageCycleOrder, language);
        if (startIndex < 0) startIndex = 0;
        int count = LanguageCycleOrder.Length;

        for (int i = 1; i < count; i++)
        {
            var candidate = LanguageCycleOrder[(startIndex + i) % count];
            if (IsLanguageAvailable(candidate))
            {
                SetLanguage(candidate);
                return;
            }
        }
        // Nenhum outro disponível — fica no actual.
    }

    /// <summary>
    /// Devolve true se o idioma já tem conteúdo localizado e pode ser seleccionado
    /// pelo jogador. Alterar aqui quando um novo idioma estiver pronto.
    ///
    /// <b>Para activar um idioma:</b> adicionar a condição abaixo, preencher os
    /// dicionários em <see cref="LocalizationManager"/> e garantir que as fontes
    /// TMP suportam o charset (ver Guia_HUD_Localizacao.md).
    /// </summary>
    public static bool IsLanguageAvailable(GameLanguage lang)
    {
        return lang switch
        {
            GameLanguage.Portugues => true,
            // English   => true,  // ← descomentar quando tradução estiver completa
            // Espanhol  => true,
            // Frances   => true,
            // Japones   => true,
            _ => false,
        };
    }

    /// <summary>Nome de exibição nativo do idioma (usado pelo seletor de idioma na UI).</summary>
    public static string LanguageDisplayName(GameLanguage lang) => lang switch
    {
        GameLanguage.Portugues => "Português",
        GameLanguage.English   => "English",
        GameLanguage.Espanhol  => "Español",
        GameLanguage.Frances   => "Français",
        GameLanguage.Japones   => "日本語",
        _ => lang.ToString(),
    };

    public void SetScreenShakeEnabled(bool value)
    {
        screenShakeEnabled = value;
        PlayerPrefs.SetInt(PrefScreenShake, value ? 1 : 0);
        NotifyChanged();
    }

    public void SetReducedFlashes(bool value)
    {
        reducedFlashes = value;
        PlayerPrefs.SetInt(PrefReducedFlashes, value ? 1 : 0);
        NotifyChanged();
    }

    // ---- Auras Pós-game ----

    public void SetApoloAuraEnabled(bool value)
    {
        apoloAuraEnabled = value;
        PlayerPrefs.SetInt(PrefApoloAura, value ? 1 : 0);
        NotifyChanged();
    }

    public void SetGaiaAuraEnabled(bool value)
    {
        gaiaAuraEnabled = value;
        PlayerPrefs.SetInt(PrefGaiaAura, value ? 1 : 0);
        NotifyChanged();
    }

    public void SetZeusAuraEnabled(bool value)
    {
        zeusAuraEnabled = value;
        PlayerPrefs.SetInt(PrefZeusAura, value ? 1 : 0);
        NotifyChanged();
    }

    private void NotifyChanged() => SettingsChanged?.Invoke();

    // ---------------- Persistência ----------------

    private void LoadSettings()
    {
        gaiaVoiceDubbed = PlayerPrefs.GetInt(PrefGaiaVoiceDubbed, gaiaVoiceDubbed ? 1 : 0) != 0;
        textSpeed = PlayerPrefs.GetFloat(PrefTextSpeed, textSpeed);
        textSize = (TextSize)PlayerPrefs.GetInt(PrefTextSize, (int)textSize);
        vibrationEnabled = PlayerPrefs.GetInt(PrefVibration, vibrationEnabled ? 1 : 0) != 0;
        screenShakeEnabled = PlayerPrefs.GetInt(PrefScreenShake, screenShakeEnabled ? 1 : 0) != 0;
        reducedFlashes = PlayerPrefs.GetInt(PrefReducedFlashes, reducedFlashes ? 1 : 0) != 0;

        apoloAuraEnabled = PlayerPrefs.GetInt(PrefApoloAura, apoloAuraEnabled ? 1 : 0) != 0;
        gaiaAuraEnabled  = PlayerPrefs.GetInt(PrefGaiaAura,  gaiaAuraEnabled  ? 1 : 0) != 0;
        zeusAuraEnabled  = PlayerPrefs.GetInt(PrefZeusAura,  zeusAuraEnabled  ? 1 : 0) != 0;

        // Idioma: usa o pref guardado; se for a primeira execução (pref ausente),
        // tenta detectar automaticamente pelo idioma do sistema (cross-platform:
        // Windows, Switch, iOS, Android — Unity expõe Application.systemLanguage
        // em todas as plataformas suportadas).
        if (PlayerPrefs.HasKey(PrefLanguage))
        {
            language = (GameLanguage)PlayerPrefs.GetInt(PrefLanguage, (int)language);
        }
        else
        {
            language = DetectSystemLanguage();
            // Guarda imediatamente para que chamadas futuras não re-detectem.
            PlayerPrefs.SetInt(PrefLanguage, (int)language);
        }

        // Garante que o idioma carregado ainda está disponível (ex: remoção de
        // idioma experimental entre versões cai de volta para Português).
        if (!IsLanguageAvailable(language))
            language = GameLanguage.Portugues;
    }

    /// <summary>
    /// Mapeia <see cref="Application.systemLanguage"/> para o <see cref="GameLanguage"/>
    /// disponível mais próximo.
    ///
    /// <b>Cadeia de fallback:</b>
    /// 1. Tenta o idioma exacto do sistema.
    /// 2. Se não estiver disponível, tenta Inglês (idioma de fallback global).
    /// 3. Se Inglês não estiver disponível (fase actual), usa Português.
    ///
    /// <b>Nota Switch:</b> Unity mapeia o idioma do sistema Switch para
    /// <c>Application.systemLanguage</c> sem necessidade de código específico
    /// de plataforma.
    /// </summary>
    private static GameLanguage DetectSystemLanguage()
    {
        GameLanguage exact = Application.systemLanguage switch
        {
            SystemLanguage.Portuguese => GameLanguage.Portugues,
            SystemLanguage.English    => GameLanguage.English,
            SystemLanguage.Spanish    => GameLanguage.Espanhol,
            SystemLanguage.French     => GameLanguage.Frances,
            SystemLanguage.Japanese   => GameLanguage.Japones,
            _                         => GameLanguage.English, // fallback global → EN
        };

        if (IsLanguageAvailable(exact)) return exact;

        // Fallback: Inglês → Português
        if (IsLanguageAvailable(GameLanguage.English)) return GameLanguage.English;
        return GameLanguage.Portugues;
    }
}
